SELECT COUNT(*) AS successful_logins
FROM authentications
WHERE result = 'success';

SELECT DISTINCT auth_type
FROM authentications
WHERE logged_in = 1;

SELECT COUNT(*) AS unhandled_event_count
FROM events
WHERE handled_by IS NULL;

SELECT result, COUNT(auth_id) AS total_attempts
FROM authentications
GROUP BY result;

SELECT MAX(confidence_score) AS max_confidence
FROM authentications
WHERE auth_type = 'face' AND result = 'success';
